  ('fire-eq-tech-moex-00766', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '在應設置室內消防栓設備之場所，但設有室外消防栓設備時，在第一層水平距離 X 公尺以下、 第二層步行距離Y公尺以下有效滅火範圍內，室內消防栓設備限於第一層、第二層免設。X、Y 分別為何？', '["X=20；Y=20", "X=20；Y=40", "X=40；Y=20", "X=40；Y=40"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00767', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '自動撒水設備竣工時，應做加壓試驗。但密閉乾式管系應併行空氣壓試驗，試驗時，應使空氣壓 力達到X MPa之標準，其壓力持續Y小時，漏氣減壓量應在Z MPa以下為合格。X、Y、Z分 別為何？', '["X=2.8；Y=24；Z=0.01", "X=2.8；Y=12；Z=0.1", "X=0.28；Y=12；Z=0.1", "X=0.28；Y=24；Z=0.01"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00768', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '中央主管機關認定儲存大量可燃物之場所天花板高度超過X公尺，或其他場所天花板高度超過Y 公尺者，應採用放水型撒水頭。X、Y分別為何？', '["X=5；Y=10", "X=6；Y=20", "X=6；Y=10", "X=10；Y=5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00769', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '密閉乾式或預動式自動撒水設備，下列設置規定何者正確？', '["密閉乾式或預動式流水檢知裝置一次側之加壓空氣，其空氣壓縮機為專用，並能在30分鐘內， 加壓達流水檢知裝置二次側配管之設定壓力值", "流水檢知裝置一次側之減壓警報設於平時有人處", "撒水頭動作後，流水檢知裝置應在30秒內，使撒水頭放水", "撒水頭使用向上型。但配管能採取有效措施者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00770', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '開放式自動撒水設備之自動及手動啟動裝置，下列設置規定何者正確？', '["受信總機設在平時有人處，且火災時，能立即操作啟動裝置者，得免設自動啟動裝置", "感知撒水頭與探測器均動作後，才能啟動一齊開放閥及加壓送水裝置", "感知撒水頭使用標示溫度在75度以下者，每20平方公尺設置1個", "感知撒水頭設在裝置面距樓地板面高度6公尺以下，且能有效探測火災處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00771', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '使用密閉式撒水頭之自動撒水設備末端之查驗閥，下列設置規定何者正確？', '["管徑在50毫米以上", "查驗閥依各流水檢知裝置配管系統配置，並接裝在建築物各層放水壓力最低之最遠支管末端", "查驗閥之一次側設有與撒水頭同等放水性能之限流孔，二次側設壓力表", "距離地板面之高度在1.5公尺以下，並附有排水管裝置，並標明末端查驗閥字樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00772', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '有關水霧滅火設備，下列設置規定何者錯誤？', '["每一水霧噴頭之有效半徑在2.1公尺以下", "放射區域，指一只一齊開放閥啟動放射之區域，每一區域以50平方公尺為原則", "放射區域有二區域以上者，其主管管徑應在100毫米以上", "水霧滅火設備之水源容量，應保持5.4立方公尺以上。但放射區域在二區域以上者，應保持10.8 立方公尺以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00773', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '移動式泡沫滅火設備之加壓送水裝置使用消防幫浦時，若同一樓層設3個泡沫消防栓箱時，其出 水量應在每分鐘多少公升以上？', '["70", "130", "260", "390"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00774', 'fire-eq-tech', 'fire-eq-tech-moex-108-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '有一總機室，設置二氧化碳滅火設備，採全區放射方式，其每立方公尺防護區域所需滅火藥劑量 為多少公斤？', '["1.5", "1.2", "1.0", "0.9"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "3423e61b4ba4", "answer_pdf_sha1": "26509f05b606", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0910", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
